{
  "source": "locked_product_design_baseline",
  "project_name": "Superset Fronting Showcase 0.2.0",
  "baseline_locked_at": "2026-06-06T21:20:08.196Z",
  "requirements": {
    "id": "req-fe8cb490-b6eb-4b01-9d64-5c310fa64629",
    "title": "Drafted Product Requirements",
    "data": {
      "auth": {
        "purpose_binding": true,
        "scoped_authority": true,
        "delegation_tokens": true
      },
      "audit": {
        "durable": true,
        "searchable": true
      },
      "scale": {
        "shape_preference": "production_single_service",
        "high_availability": false
      },
      "trust": {
        "mode": "signed",
        "checkpoints": false
      },
      "system": {
        "name": "superset-fronting-showcase-0-2-0",
        "domain": "analytics_operations",
        "deployment_intent": "public_http_service"
      },
      "lineage": {
        "task_id": true,
        "invocation_id": true,
        "client_reference_id": true,
        "parent_invocation_id": true
      },
      "transports": {
        "grpc": false,
        "http": true,
        "stdio": false
      },
      "permissions": {
        "preflight_discovery": true,
        "restricted_vs_denied": true
      },
      "risk_profile": {},
      "business_constraints": {
        "assistant_drafted_requirements_count": 12,
        "assistant_drafted_requirements_summary": "Expose only governed analytics capabilities to agents: The product shall present a governed analytics capability surface for discovering allowed analytics context, answering bounded analytics questions, creating chart previews, requesting chart publication, preparing dashboard drafts, and preparing dataset drafts. Agents shall not receive raw SQL, raw chart, raw dashboard, raw database, or MCP-style tool exposure.\nUse native Superset REST APIs as the backend execution binding: The product shall integrate with Apache Superset through native REST APIs as the durable backend for governed analytics operations. The implementation shall treat MCP only as a comparison surface and not as the execution interface for the governed contract.\nProvide governed discovery of actor-visible analytics context: The product shall support discovery of allowed datasets, charts, dashboards, metrics, and dimensions within an actor-visible workspace scope. Discovery results shall be limited to allowlisted and visible assets and returned as read-only catalog summaries.\nAnswer analytics questions only within bounded dataset and metric constraints: The product shall answer analytics questions only when the request is anchored to an allowed dataset and governed metric or dimension context. Execution shall remain bounded by declared dataset scope, metric and dimension constraints, result grain, row limits, and audit constraints. Raw SQL shall not be accepted as an input.\nDefault creation workflows to preview-only outcomes: The product shall default chart creation and dashboard preparation workflows to preview-only behavior. Preview flows shall not save or publish artifacts unless an explicit approval-gated path is completed.\nRequire approval for publication and dataset creation actions: The product shall require explicit approval before saving or updating charts, publishing dashboards, or creating virtual or semantic dataset artifacts. The system shall capture a publish or creation reason and stop at an approval boundary until an authorized analytics owner or BI administrator approves the request.\nReturn clarification-required outcomes when required context is missing: The product shall return a clarification-required outcome when required context is missing, including missing dataset reference, metric, chart preview reference, dashboard scope, or publish reason. The clarification response shall identify the missing governed input needed to continue.\nEnforce allowlists and sensitive-dimension restrictions beyond backend RBAC: The product shall enforce dataset, chart, dashboard, and database allowlists and may restrict owner-level, row-level, customer-level, or otherwise sensitive dimensions even when the downstream platform would technically allow access. Governance rules shall take precedence over raw backend reachability.\nLimit backend options to bounded provider controls: The product shall allow backend options only for bounded provider controls such as selected fields, pagination, chart rendering format, or preview output format. Backend options shall not permit arbitrary SQL execution, unbounded export, database switching, allowlist bypass, or hidden publication behavior.\nDeny prohibited raw access and bypass behaviors: The product shall deny requests for raw SQL, raw exports, unrestricted SQL execution, protected database access, dashboard publication bypass, and unapproved saved-query creation. Denial outcomes shall be explicit and audit-friendly.\nProduce audit-friendly records for governed actions, denials, and approvals: The product shall produce audit-friendly outcomes for discovery, bounded answers, previews, approval requests, denials, and clarification stops. Records shall preserve enough context to explain what was requested, what governance boundary applied, and why the system returned the resulting posture.\nRequire real integration evidence before contract generation: Before contract generation, the product definition process shall include real integration evidence for the downstream Superset operations in scope, such as uploaded API documentation, schemas, permission matrices, live discovery, or manually entered operations. The process shall not infer backend operations from project name or domain alone."
      }
    }
  },
  "scenarios": [
    {
      "id": "scn-e02e39fb-ad01-4d83-8423-986627167f3c",
      "title": "Deny requests for raw SQL, unrestricted export, or protected access",
      "data": {
        "scenario": {
          "name": "deny-requests-for-raw-sql-unrestricted-export-or-protected-access",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The brief explicitly denies raw SQL, raw exports, protected database access, dashboard publication bypass, and similar unrestricted operations.",
            "capability": "superset.analytics.answer_question",
            "confidence": "high",
            "time_scope": "At request time before backend execution",
            "actor_context": "Any actor attempting to use a disallowed analytics path",
            "business_scope": "Hard denial of non-governed analytics operations"
          },
          "category": "cross_service",
          "narrative": "A user attempts to step outside the governed analytics surface by asking for raw SQL, unrestricted export, or direct protected access. The service stops the request and returns a governed denial rather than trying to partially comply.",
          "expected_behavior": [
            "The service should deny disallowed operations consistently across actors unless a separate approved capability exists.",
            "No hidden fallback to raw backend tools should occur.",
            "Denial reasons should be explicit enough for user understanding and audit review."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3"
          ],
          "expected_anip_support": [
            "Make denial rules part of the contract rather than relying on prompt-only guardrails.",
            "Prevent backend mappings that would enable arbitrary SQL, unrestricted export, or allowlist bypass.",
            "Capture denial outcomes for audit and governance review."
          ],
          "participating_services": [
            "Superset Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-3ae26298-27b6-4a24-ab8f-c1f6feb79776",
      "title": "Prepare a governed dataset draft without accepting raw SQL",
      "data": {
        "scenario": {
          "name": "prepare-a-governed-dataset-draft-without-accepting-raw-sql",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source defines dataset draft preparation, approval-gated posture, and explicit denial of raw SQL from agents.",
            "capability": "superset.dataset.draft.prepare",
            "confidence": "high",
            "time_scope": "Pre-implementation design stage before dataset creation",
            "actor_context": "Dataset draft requester proposing a new governed dataset",
            "business_scope": "Approval-gated semantic or virtual dataset drafting"
          },
          "category": "cross_service",
          "narrative": "A requester needs a new governed dataset for future analytics use. Instead of supplying SQL, they describe the dataset purpose and query intent, and the service prepares a draft for approval within database and source-table governance.",
          "expected_behavior": [
            "Raw SQL must be refused as an agent input.",
            "Dataset creation should not occur automatically from the draft request.",
            "Protected database access, allowlist bypass, and unapproved saved-query creation should be denied."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Translate business dataset intent into a governed draft workflow rather than direct SQL tooling.",
            "Enforce database, source-table, metric, and approval boundaries before any creation path.",
            "Record audit-friendly draft and approval status."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-9811b68b-f387-4c8f-bf70-0d16ef63b110",
      "title": "Prepare a dashboard draft or update proposal without publishing",
      "data": {
        "scenario": {
          "name": "prepare-a-dashboard-draft-or-update-proposal-without-publishing",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source defines dashboard draft preparation clearly, but does not provide a separate explicit publish capability in this brief, so the scenario should stay at draft posture.",
            "capability": "superset.dashboard.draft.prepare",
            "confidence": "medium",
            "time_scope": "Planning and review stage before any publish decision",
            "actor_context": "Analytics creator or owner preparing dashboard structure",
            "business_scope": "Preview-only dashboard composition and update proposal"
          },
          "category": "cross_service",
          "narrative": "A user wants to organize approved or previewed charts into a dashboard concept for a business objective. The service prepares a dashboard draft or update proposal, including layout hints and audience context, but does not publish it as part of this step.",
          "expected_behavior": [
            "Dashboard preparation should remain preview-only in this scenario.",
            "The service should not bypass approval or hidden publication paths.",
            "If dashboard scope is missing, the flow should stop for clarification."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Support draft-oriented dashboard composition without exposing raw dashboard APIs directly to agents.",
            "Preserve approval boundaries between draft preparation and any later publication step.",
            "Audit draft preparation and review outcomes."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-17531fbb-e6d7-4800-8268-c62b66a54f43",
      "title": "Request chart publication after preview, with approval gating",
      "data": {
        "scenario": {
          "name": "request-chart-publication-after-preview-with-approval-gating",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The brief explicitly defines chart publish request inputs, approval gating, and approver roles of analytics owner or BI admin.",
            "capability": "superset.chart.publish.request",
            "confidence": "high",
            "time_scope": "After preview review and before persistent publication",
            "actor_context": "Analytics creator requesting publication; analytics owner or BI admin as approver",
            "business_scope": "Approval-gated chart save or update workflow"
          },
          "category": "cross_service",
          "narrative": "A creator is satisfied with a chart preview and wants it saved or updated for broader use. The service packages the request with dashboard scope and reason, then routes it through the required approval boundary before any persistent publication occurs.",
          "expected_behavior": [
            "Publication should never occur without a valid preview reference and publish reason.",
            "Creators can prepare and request publication, but approval is required before persistence unless the actor is already authorized.",
            "The service should make approval status explicit rather than implying a save already happened."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Represent approval-required as a first-class governed outcome.",
            "Bind publication only to approved, policy-compliant requests.",
            "Maintain approval records and audit trace for the request and decision."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-5aadea98-1381-4fcc-822f-7e2b2a9c94b3",
      "title": "Stop for clarification when required analytics context is missing",
      "data": {
        "scenario": {
          "name": "stop-for-clarification-when-required-analytics-context-is-missing",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly states that missing dataset, metric, chart preview, dashboard scope, or publish reason returns clarification_required.",
            "capability": "superset.analytics.answer_question",
            "confidence": "high",
            "time_scope": "At request time before execution or approval routing",
            "actor_context": "Any otherwise authorized actor using governed analytics capabilities",
            "business_scope": "Input completeness and safe continuation rules across analytics workflows"
          },
          "category": "cross_service",
          "narrative": "A user provides an incomplete request, such as asking a question without naming the dataset or requesting publication without a publish reason. The service pauses and asks for the missing governed input instead of inferring or defaulting silently.",
          "expected_behavior": [
            "The service should not invent dataset, metric, preview, dashboard scope, or publish reason values.",
            "Clarification should be targeted to the missing governed input rather than broad or generic.",
            "No backend write or publish action should occur before clarification is resolved."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Make required inputs explicit in the capability contract.",
            "Return structured clarification outcomes instead of hidden fallback behavior.",
            "Preserve auditability of why execution did not proceed."
          ],
          "participating_services": [
            "Superset Governance Service"
          ]
        }
      }
    },
    {
      "id": "scn-c1f0f7ee-e8fc-4a09-8f4f-7fda4d7e8476",
      "title": "Create a chart preview without saving it",
      "data": {
        "scenario": {
          "name": "create-a-chart-preview-without-saving-it",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source defines chart preview creation with required inputs and explicitly states that charts are not saved by default.",
            "capability": "superset.chart.preview.create",
            "confidence": "high",
            "time_scope": "Interactive design step before any publication request",
            "actor_context": "Analytics creator or owner preparing a visualization",
            "business_scope": "Preview-first chart creation under metric and dimension governance"
          },
          "category": "orchestration",
          "narrative": "A creator wants to visualize an allowed metric from an allowed dataset. They request a chart preview using governed visualization intent, and the service produces a preview artifact without creating or updating a saved chart.",
          "expected_behavior": [
            "Preview creation should remain non-persistent by default.",
            "Only governed metrics, dimensions, and filters should be used.",
            "The service should deny attempts to bypass preview posture and save directly."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Separate preview semantics from publication semantics in the contract.",
            "Enforce preview-only defaults and bounded rendering options.",
            "Audit preview generation without implying publication."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-160c9b01-ff2d-4644-b3ec-07ca2738bf2e",
      "title": "Answer a governed analytics question against an allowed dataset",
      "data": {
        "scenario": {
          "name": "answer-a-governed-analytics-question-against-an-allowed-dataset",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The brief clearly defines bounded analytics answering, required dataset reference, optional governed inputs, preview/read-only posture, and denial of raw SQL.",
            "capability": "superset.analytics.answer_question",
            "confidence": "high",
            "time_scope": "Interactive question answering during analysis",
            "actor_context": "Analytics consumer, creator, or owner with bounded analytics access",
            "business_scope": "Read-only governed analytics answers over allowlisted datasets"
          },
          "category": "cross_service",
          "narrative": "A user asks a business question such as understanding performance over a time window, but must do so within an allowed dataset and governed metric and dimension boundaries. The service returns a bounded answer rather than exposing query construction or SQL execution.",
          "expected_behavior": [
            "The service should require dataset_ref and stop for clarification if it is missing.",
            "Only governed metrics, dimensions, filters, and result grain should be allowed.",
            "Raw SQL must not be accepted as input or exposed as output.",
            "Sensitive, owner-level, row-level, or customer-level dimensions may be restricted even if downstream RBAC would allow them."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Map business questions to bounded analytics execution without exposing raw Superset query tools.",
            "Enforce metric, dimension, row-limit, and allowlist policy before backend execution.",
            "Return explicit clarification or denial outcomes when policy or required inputs are not satisfied.",
            "Capture audit-friendly records of the governed answer path."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-520cae9d-47c4-4006-adfb-6a468c2353e3",
      "title": "Discover allowed analytics context within a governed workspace",
      "data": {
        "scenario": {
          "name": "discover-allowed-analytics-context-within-a-governed-workspace",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly defines a discovery capability with required inputs, read-only posture, and actor-visible catalog summaries.",
            "capability": "superset.analytics.discover_context",
            "confidence": "high",
            "time_scope": "Ad hoc at the start of an analytics task",
            "actor_context": "Analytics consumer or creator with access to a governed workspace",
            "business_scope": "Governed analytics discovery over allowlisted Superset assets"
          },
          "category": "cross_service",
          "narrative": "A user starts with a business question but first needs to understand what governed analytics assets are available. They provide a workspace scope and search query, and the service returns only the datasets, charts, dashboards, metrics, and dimensions they are allowed to see.",
          "expected_behavior": [
            "Results are read-only and limited to actor-visible, allowlisted analytics assets.",
            "The service exposes governed analytics context rather than raw Superset tools or backend objects.",
            "If workspace scope is missing or invalid, the flow should stop for clarification."
          ],
          "orchestration_steps": [
            "1",
            "2",
            "3",
            "4"
          ],
          "expected_anip_support": [
            "Enforce workspace and asset visibility before any backend lookup.",
            "Present a business-level discovery capability instead of direct dataset, chart, dashboard, or database tools.",
            "Record audit-friendly discovery outcomes."
          ],
          "participating_services": [
            "Superset Governance Service",
            "native Superset REST API adapter"
          ]
        }
      }
    }
  ],
  "service_design": {
